// ── EmailJS ────────────────────────────────────────────────────────────────────
const EMAILJS_SERVICE_ID  = "YOUR_SERVICE_ID";
const EMAILJS_TEMPLATE_ID = "YOUR_TEMPLATE_ID";
const EMAILJS_PUBLIC_KEY  = "YOUR_PUBLIC_KEY";
const MANAGER_EMAIL       = "lukas.weidinger@topgolfwien.com";

async function sendEmail(subject, body) {
  try {
    const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ service_id: EMAILJS_SERVICE_ID, template_id: EMAILJS_TEMPLATE_ID, user_id: EMAILJS_PUBLIC_KEY,
        template_params: { to_email: MANAGER_EMAIL, subject, message: body } }),
    });
    return res.ok;
  } catch { return false; }
}

// ── Storage ────────────────────────────────────────────────────────────────────
async function loadData(key) {
  try { const r = await window.storage.get(key); return r ? JSON.parse(r.value) : []; } catch { return []; }
}
async function saveData(key, data) {
  try { await window.storage.set(key, JSON.stringify(data)); } catch {}
}

